def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 1:
            priorities[i] = float('inf')
            continue
        score = 0
        complexity = 1
        for j in range(1, 6):
            if ratio < j * 0.15:
                score += j * (1 - ratio) * np.exp(-j / 5)
                complexity += j
            else:
                score += j * ratio / 3 * (1 + np.sin(ratio * j * np.pi))
                complexity += j ** 2
        if cap % 3 == 0:
            modifier = np.log1p(cap) * np.sqrt(complexity)
        elif cap % 2 == 0:
            modifier = np.log1p(cap) / np.sqrt(complexity)
        else:
            modifier = (np.sqrt(cap) + np.log1p(complexity)) / (cap + 1)
        if ratio < 0.3:
            penalty = ((0.3 - ratio) ** 2) * cap / (complexity + 1)
            priorities[i] = (score * modifier) - penalty
        elif ratio > 0.8:
            penalty = ((ratio - 0.8) ** 3) * complexity / (cap + 1)
            priorities[i] = (score * modifier) - penalty
        else:
            bonus = np.sin(ratio * np.pi * complexity) * cap / (complexity + 1)
            priorities[i] = (score * modifier) + bonus
        if priorities[i] < 0:
            priorities[i] = 0
    return priorities
